// 自動生成ファイル。直接編集せず prototype/index.html を編集して `npm run sync-html` を実行
export default "<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, viewport-fit=cover\">\n<title>ADHDo — 今日のタイムライン</title>\n<style>\n:root{\n  /* カテゴリ色(ダーク背景でCVD/コントラスト検証済み) */\n  --c-workout:#f4526a;  /* 筋トレ = 赤 */\n  --c-work:#4a8df8;     /* Work = 青 */\n  --c-meal:#d97706;     /* 食事 = オレンジ */\n  --c-sleep:#9d7bf5;    /* 睡眠 = 紫 */\n  --c-routine:#0da06f;  /* ルーティン = 緑 */\n  --c-meeting:#84a31c;  /* ミーティング = 黄緑 */\n  --brand:#7bc5ba;      /* ロゴのティール */\n\n  --bg:#0d1017;\n  --surface:#131722;\n  --surface-2:#1a2030;\n  --line:#232b3d;\n  --ink:#e8ecf4;\n  --ink-2:#98a2b8;\n  --ink-3:#5f6a82;\n  --footer-h:64px;\n}\n*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent}\nhtml,body{height:100%}\nbody{\n  background:var(--bg);color:var(--ink);\n  font-family:-apple-system,BlinkMacSystemFont,\"Hiragino Sans\",\"Noto Sans JP\",\"Segoe UI\",sans-serif;\n  font-size:15px;line-height:1.55;\n  max-width:480px;margin:0 auto;\n}\nbutton{font-family:inherit;cursor:pointer}\n\n/* ============ レイアウト ============ */\n.screen{display:none;padding:0 16px calc(var(--footer-h) + 24px)}\n.screen.active{display:block}\nheader.app{\n  position:sticky;top:0;z-index:20;\n  background:var(--bg);\n  box-shadow:0 8px 16px -8px var(--bg);\n  padding:12px 2px 8px;\n}\n.head-row{display:flex;justify-content:space-between;align-items:flex-start;gap:12px}\nheader.app h1{font-size:20px;font-weight:700;letter-spacing:.02em}\nheader.app .date{font-size:13px;color:var(--ink-2);margin-top:2px}\n.brand{display:flex;align-items:center;gap:8px}\n.brand svg{flex:none}\n.logo-word{font-size:17px;font-weight:800;color:var(--ink);letter-spacing:.04em}\n.logo-word .o{color:var(--brand)}\n.live-clock{color:var(--brand);font-weight:700;font-variant-numeric:tabular-nums;margin-left:7px}\n#scr-home header.app .date{font-size:11.5px;margin-top:3px}\n.ach-mini{min-width:134px;flex:none;padding-top:2px}\n.ach-mini-top{display:flex;justify-content:flex-end;align-items:baseline;gap:6px;font-size:10px;color:var(--ink-2)}\n.ach-mini-top b{font-size:16px;color:var(--ink);font-variant-numeric:tabular-nums}\n.ach-mini .ach-bar{height:5px;margin-top:4px}\n.ach-mini .ach-meta{font-size:9.5px;margin-top:3px;text-align:right;font-variant-numeric:tabular-nums}\n\n/* ============ 24hチャート ============ */\n.clock-wrap{position:relative;margin:4px auto 6px;max-width:360px}\n.clock-wrap svg{display:block;width:100%;height:auto}\n.clock-center{\n  position:absolute;inset:0;display:flex;flex-direction:column;\n  align-items:center;justify-content:center;text-align:center;pointer-events:none;\n}\n.clock-center .big-time{\n  font-size:34px;font-weight:800;letter-spacing:.01em;\n  font-variant-numeric:tabular-nums;line-height:1.1;\n}\n.clock-center .day{font-size:11px;color:var(--ink-3);margin-bottom:2px;letter-spacing:.08em}\n.clock-center .task-chip{\n  display:inline-flex;align-items:center;gap:6px;margin-top:8px;\n  background:var(--surface-2);border:1px solid var(--line);\n  border-radius:99px;padding:4px 12px;font-size:12px;font-weight:600;\n}\n.clock-center .task-chip .dot{width:8px;height:8px;border-radius:50%}\n.clock-center .remain{font-size:11px;color:var(--ink-2);margin-top:5px}\n.seg{transition:opacity .25s,filter .25s;cursor:pointer}\n.seg.dim{opacity:.5;filter:saturate(.75)}\n.chart-tip{\n  position:absolute;left:50%;top:6px;transform:translateX(-50%);\n  background:var(--surface-2);border:1px solid var(--line);border-radius:10px;\n  padding:7px 14px;font-size:12px;white-space:nowrap;display:none;z-index:5;\n  box-shadow:0 6px 20px rgba(0,0,0,.45);\n}\n.chart-tip.show{display:block}\n.chart-tip b{font-size:13px}\n.chart-tip .t{color:var(--ink-2);font-variant-numeric:tabular-nums}\n\n.legend{\n  display:flex;flex-wrap:wrap;gap:6px 14px;justify-content:center;\n  margin:2px auto 22px;font-size:12px;color:var(--ink-2);\n}\n.legend .item{display:flex;align-items:center;gap:6px}\n.legend .dot{width:9px;height:9px;border-radius:50%}\n.legend b{color:var(--ink);font-weight:600}\n\n/* ============ タイムライン ============ */\n.tl-head{display:flex;align-items:baseline;justify-content:space-between;margin:4px 2px 12px}\n.tl-head h2{font-size:16px;font-weight:700}\n.tl-head span{font-size:12px;color:var(--ink-3)}\n.tl{position:relative;padding-left:64px}\n.tl::before{\n  content:\"\";position:absolute;left:56px;top:8px;bottom:8px;width:2px;\n  background:var(--line);border-radius:2px;\n}\n.tl-item{position:relative;margin-bottom:14px}\n.tl-time{\n  position:absolute;left:-64px;top:14px;width:48px;text-align:right;\n  font-size:13px;font-weight:600;color:var(--ink-2);\n  font-variant-numeric:tabular-nums;transition:all .3s;\n}\n.tl-node{\n  position:absolute;left:-12px;top:19px;width:10px;height:10px;border-radius:50%;\n  background:var(--surface);border:2px solid var(--cat);z-index:2;transition:all .3s;\n}\n.tl-card{\n  background:var(--surface);border:1px solid var(--line);border-radius:14px;\n  padding:13px 14px;border-left:4px solid var(--cat);\n  transition:all .35s ease;\n}\n.tl-card .row1{display:flex;align-items:center;gap:8px}\n.tl-card .title{font-size:15px;font-weight:700;flex:1}\n.tl-card .range{font-size:12px;color:var(--ink-2);font-variant-numeric:tabular-nums;white-space:nowrap}\n.tl-card .cat-tag{\n  font-size:10px;font-weight:700;letter-spacing:.05em;color:var(--cat);\n  border:1px solid color-mix(in srgb,var(--cat) 45%,transparent);\n  border-radius:6px;padding:1px 7px;\n}\n.subs{margin-top:10px;border-top:1px dashed var(--line);padding-top:8px;display:grid;gap:5px}\n.sub{\n  display:flex;align-items:center;gap:8px;font-size:13px;color:var(--ink-2);\n  transition:opacity .3s;\n}\n.sub .s-dot{width:6px;height:6px;border-radius:50%;background:var(--ink-3);flex:none;transition:all .3s}\n.sub .s-name{flex:1}\n.sub .s-time{font-size:12px;color:var(--ink-3);font-variant-numeric:tabular-nums;white-space:nowrap}\n.sub.done{opacity:.45}\n.sub.done .s-name{text-decoration:line-through}\n.sub.active{color:var(--ink);font-weight:600}\n.sub.active .s-dot{background:var(--cat);box-shadow:0 0 8px var(--cat);transform:scale(1.35)}\n.sub.active .s-time{color:var(--cat)}\n\n/* --- NOW 強調(順序はそのまま・その場で大きく) --- */\n.tl-item.now .tl-time{font-size:17px;color:var(--cat);font-weight:800}\n.tl-item.now .tl-node{\n  width:14px;height:14px;left:-14px;background:var(--cat);\n  box-shadow:0 0 0 5px color-mix(in srgb,var(--cat) 25%,transparent),0 0 18px var(--cat);\n  animation:pulse 2s infinite;\n}\n.tl-item.now .tl-card{\n  padding:18px 16px;transform:scale(1.02);transform-origin:left center;\n  background:linear-gradient(135deg,color-mix(in srgb,var(--cat) 14%,var(--surface)),var(--surface) 70%);\n  border-color:color-mix(in srgb,var(--cat) 55%,var(--line));\n  box-shadow:0 4px 28px color-mix(in srgb,var(--cat) 28%,transparent);\n}\n.tl-item.now .title{font-size:19px}\n.tl-item.now .range{font-size:13px;color:var(--ink)}\n.now-badge{\n  display:none;align-items:center;gap:5px;\n  background:var(--cat);color:#fff;font-size:10px;font-weight:800;letter-spacing:.1em;\n  border-radius:99px;padding:2px 9px;\n}\n.now-badge::before{content:\"\";width:6px;height:6px;border-radius:50%;background:#fff;animation:blink 1.2s infinite}\n.tl-item.now .now-badge{display:inline-flex}\n.tl-item.now .cat-tag{display:none}\n.now-progress{display:none;margin-top:12px}\n.tl-item.now .now-progress{display:block}\n.now-progress .bar{height:6px;background:var(--surface-2);border-radius:99px;overflow:hidden}\n.now-progress .fill{height:100%;background:var(--cat);border-radius:99px;transition:width .5s}\n.now-progress .meta{display:flex;justify-content:space-between;font-size:11px;color:var(--ink-2);margin-top:5px;font-variant-numeric:tabular-nums}\n.tl-item.past .tl-card{opacity:.55}\n.tl-item.past .tl-time{opacity:.55}\n@keyframes pulse{0%,100%{box-shadow:0 0 0 5px color-mix(in srgb,var(--cat) 25%,transparent),0 0 18px var(--cat)}50%{box-shadow:0 0 0 8px color-mix(in srgb,var(--cat) 12%,transparent),0 0 26px var(--cat)}}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}\n.tl-item.flash .tl-card{box-shadow:0 0 0 2px var(--cat),0 4px 28px color-mix(in srgb,var(--cat) 35%,transparent)}\n\n/* ============ 達成率・ビュー切り替え ============ */\n.ach{background:var(--surface);border:1px solid var(--line);border-radius:14px;padding:12px 14px;margin-top:10px}\n.ach-top{display:flex;justify-content:space-between;align-items:baseline;font-size:12px;color:var(--ink-2)}\n.ach-top b{font-size:20px;color:var(--ink);font-variant-numeric:tabular-nums}\n.ach-bar{height:8px;background:var(--surface-2);border-radius:99px;overflow:hidden;margin-top:8px}\n.ach-fill{height:100%;border-radius:99px;background:linear-gradient(90deg,var(--brand),var(--c-routine));transition:width .4s}\n.ach-meta{font-size:11px;color:var(--ink-3);margin-top:5px}\n.seg-tabs{display:flex;background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:4px;margin:9px 0 2px}\n.seg-tabs button{flex:1;background:none;border:none;color:var(--ink-2);font-size:13px;font-weight:600;padding:8px;border-radius:9px}\n.seg-tabs button.sel{background:var(--brand);color:#0d1017;font-weight:700}\n\n/* 完了チェック */\n.s-check,.ev-check{\n  width:20px;height:20px;border-radius:50%;flex:none;padding:0;\n  border:1.5px solid var(--ink-3);background:none;color:#fff;font-size:12px;line-height:1;\n  display:flex;align-items:center;justify-content:center;transition:all .2s;\n}\n.s-check.on,.ev-check.on{background:var(--cat);border-color:var(--cat)}\n.ev-check{width:22px;height:22px}\n.sub-count{font-size:11px;color:var(--ink-3);font-variant-numeric:tabular-nums;white-space:nowrap}\n.tl-item.checked .title{text-decoration:line-through;opacity:.6}\n\n/* ============ 許す仕組み(スキップ/持ち越し) ============ */\n.quick{display:flex;gap:8px;justify-content:flex-end;margin-top:10px}\n.quick button{background:none;border:1px solid var(--line);color:var(--ink-3);border-radius:8px;padding:4px 10px;font-size:11px;font-weight:600}\n.tl-item.skipped .tl-card{opacity:.4}\n.skip-badge{font-size:10px;font-weight:700;color:var(--ink-3);border:1px solid var(--line);border-radius:6px;padding:1px 7px;white-space:nowrap}\n.carry-panel{\n  background:color-mix(in srgb,var(--brand) 10%,var(--surface));\n  border:1px solid color-mix(in srgb,var(--brand) 35%,var(--line));\n  border-radius:14px;padding:12px 14px;margin-bottom:14px;\n}\n.carry-panel h4{font-size:13px;margin-bottom:8px;color:var(--brand)}\n.carry-panel .sub{--cat:var(--brand)}\n\n/* ============ XP・レベル ============ */\n.lv-chip{\n  font-size:10px;font-weight:800;color:var(--brand);\n  border:1px solid color-mix(in srgb,var(--brand) 45%,transparent);\n  border-radius:99px;padding:1px 8px;margin-left:7px;white-space:nowrap;\n}\n.xp-bar{height:6px;background:var(--surface-2);border-radius:99px;overflow:hidden;margin-top:8px}\n.xp-fill{height:100%;background:var(--brand);border-radius:99px;transition:width .4s}\n\n/* ============ 紙吹雪 ============ */\n.confetti{position:fixed;width:8px;height:8px;border-radius:2px;pointer-events:none;z-index:99}\n\n/* ============ 集中タイマー ============ */\n.modal.center{align-items:center;padding:0 20px}\n.focus-box{\n  background:var(--surface);border:1px solid var(--line);border-radius:20px;\n  padding:28px 22px;width:100%;max-width:340px;text-align:center;\n}\n.focus-phase{font-size:11px;color:var(--ink-3);letter-spacing:.12em;font-weight:700}\n.focus-task-name{font-size:14px;font-weight:700;margin-top:4px}\n.focus-time{font-size:56px;font-weight:800;font-variant-numeric:tabular-nums;margin:8px 0 4px}\n.focus-hint{font-size:11.5px;color:var(--ink-2);margin-bottom:14px}\n.focus-btn-row{display:flex;gap:10px;justify-content:center}\n.focus-presets{display:flex;gap:8px;justify-content:center;margin-bottom:14px}\n.focus-presets .btn.sel{border-color:var(--brand);color:var(--brand)}\n.focus-open{\n  margin-top:10px;width:100%;\n  background:color-mix(in srgb,var(--cat) 18%,var(--surface-2));\n  border:1px solid color-mix(in srgb,var(--cat) 45%,transparent);\n  color:var(--ink);border-radius:10px;padding:9px;font-size:13px;font-weight:700;\n}\n\n/* ============ 予定エディタ ============ */\n.fab{\n  position:fixed;right:max(18px,calc(50% - 222px));bottom:calc(var(--footer-h) + 20px);\n  width:54px;height:54px;border-radius:50%;z-index:40;\n  background:var(--brand);border:none;color:#0d1017;font-size:30px;line-height:1;font-weight:400;\n  box-shadow:0 6px 20px color-mix(in srgb,var(--brand) 45%,transparent);\n}\n.modal{position:fixed;inset:0;z-index:60;display:none;align-items:flex-end;justify-content:center;background:rgba(5,8,14,.65)}\n.modal.show{display:flex}\n.sheet{\n  background:var(--surface);border:1px solid var(--line);border-bottom:none;\n  border-radius:20px 20px 0 0;width:100%;max-width:480px;max-height:86vh;overflow-y:auto;\n  padding:20px 18px calc(24px + env(safe-area-inset-bottom));\n}\n.sheet h3{font-size:16px;font-weight:700;margin-bottom:4px}\n.f-label{font-size:12px;color:var(--ink-2);margin:14px 0 6px;font-weight:600}\n.cat-chips{display:flex;gap:8px;flex-wrap:wrap}\n.cat-chip{border:1px solid var(--line);background:var(--surface-2);color:var(--ink-2);border-radius:99px;padding:7px 13px;font-size:12.5px;font-weight:600}\n.cat-chip.sel{color:#fff;border-color:transparent}\n.time-row{display:flex;gap:10px;align-items:center}\n.time-row input{flex:1}\n.sub-edit{display:flex;gap:6px;margin-bottom:6px;align-items:center}\n.sub-edit input[type=text]{flex:1;padding:8px 10px;min-width:0}\n.sub-edit input[type=time]{width:84px;padding:8px 4px;font-size:12px}\n.sub-del{background:none;border:none;color:var(--ink-3);font-size:18px;padding:2px 6px}\n.sheet-actions{display:flex;gap:10px;margin-top:20px}\n.sheet-actions .btn{flex:1;text-align:center;padding:12px}\n.btn.danger{color:var(--c-workout);border-color:color-mix(in srgb,var(--c-workout) 40%,transparent)}\n.ed-error{display:none;color:var(--c-workout);font-size:12px;margin-top:10px}\n.ed-error.show{display:block}\n\n/* ============ フッター ============ */\nnav.footer{\n  position:fixed;bottom:0;left:50%;transform:translateX(-50%);\n  width:100%;max-width:480px;height:var(--footer-h);z-index:50;\n  background:color-mix(in srgb,var(--surface) 92%,transparent);\n  backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);\n  border-top:1px solid var(--line);\n  display:grid;grid-template-columns:repeat(5,1fr);\n  padding-bottom:env(safe-area-inset-bottom);\n}\nnav.footer button{\n  background:none;border:none;color:var(--ink-3);\n  display:flex;flex-direction:column;align-items:center;justify-content:center;gap:3px;\n  font-size:9.5px;font-weight:600;letter-spacing:.02em;\n}\nnav.footer button svg{width:22px;height:22px;stroke:currentColor;fill:none;stroke-width:1.8;stroke-linecap:round;stroke-linejoin:round}\nnav.footer button.small{font-size:8px;letter-spacing:0}\nnav.footer button.active{color:var(--ink)}\nnav.footer button.active svg{stroke-width:2.2}\n\n/* ============ サブ画面共通 ============ */\n.panel{background:var(--surface);border:1px solid var(--line);border-radius:16px;padding:18px;margin-bottom:14px}\n.panel h3{font-size:15px;font-weight:700;margin-bottom:10px}\n.btn{\n  background:var(--surface-2);border:1px solid var(--line);color:var(--ink);\n  border-radius:10px;padding:9px 16px;font-size:13px;font-weight:600;\n}\n.btn.primary{background:var(--brand);border-color:var(--brand);color:#0d1017;font-weight:700}\n.btn.sm{padding:6px 11px;font-size:12px}\ntextarea,input[type=text],input[type=time]{\n  width:100%;background:var(--surface-2);border:1px solid var(--line);color:var(--ink);\n  border-radius:10px;padding:10px 12px;font-size:14px;font-family:inherit;outline:none;\n}\ntextarea:focus,input:focus{border-color:var(--c-work)}\n\n/* 瞑想 */\n.breath-stage{display:flex;flex-direction:column;align-items:center;padding:30px 0 10px}\n.breath-circle{\n  width:170px;height:170px;border-radius:50%;\n  background:radial-gradient(circle at 35% 30%,color-mix(in srgb,var(--c-routine) 45%,var(--surface-2)),var(--surface-2));\n  border:2px solid var(--c-routine);\n  display:flex;align-items:center;justify-content:center;\n  font-size:16px;font-weight:700;\n  transition:transform 4s ease-in-out;box-shadow:0 0 40px color-mix(in srgb,var(--c-routine) 25%,transparent);\n}\n.breath-circle.inhale{transform:scale(1.25)}\n.breath-circle.exhale{transform:scale(.85);transition-duration:8s}\n.med-timer{font-size:30px;font-weight:800;font-variant-numeric:tabular-nums;margin:18px 0 6px}\n.med-presets{display:flex;gap:8px;justify-content:center;margin:10px 0}\n.med-presets .btn.sel{border-color:var(--c-routine);color:var(--c-routine)}\n\n/* マンスリーカレンダー */\n.cal-nav{display:flex;align-items:center;justify-content:space-between;margin:8px 0 14px}\n.cal-nav b{font-size:16px}\n.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:6px}\n.cal-dow{text-align:center;font-size:11px;color:var(--ink-3);padding:2px 0}\n.cal-cell{\n  aspect-ratio:1;border-radius:10px;background:var(--surface);border:1px solid var(--line);\n  display:flex;flex-direction:column;align-items:center;justify-content:center;gap:1px;\n}\n.cal-cell .d{font-size:12px;color:var(--ink-2)}\n.cal-cell .p{font-size:9.5px;font-weight:700;font-variant-numeric:tabular-nums}\n.cal-cell.today{border:2px solid var(--brand)}\n.cal-cell.empty{background:none;border:none}\n\n/* 日記 */\n.diary-entry{border-bottom:1px solid var(--line);padding:12px 2px}\n.diary-entry:last-child{border-bottom:none}\n.diary-entry .d{font-size:11px;color:var(--ink-3);display:flex;justify-content:space-between}\n.diary-entry p{font-size:13.5px;margin-top:4px;white-space:pre-wrap}\n.diary-entry button{background:none;border:none;color:var(--ink-3);font-size:11px}\n\n/* アファメーション */\n.affirm-card{\n  background:linear-gradient(135deg,color-mix(in srgb,var(--c-sleep) 22%,var(--surface)),var(--surface));\n  border:1px solid color-mix(in srgb,var(--c-sleep) 40%,var(--line));\n  border-radius:18px;padding:44px 24px;text-align:center;margin-bottom:14px;\n  box-shadow:0 8px 30px color-mix(in srgb,var(--c-sleep) 15%,transparent);\n}\n.affirm-card .q{font-size:18px;font-weight:700;line-height:1.7}\n.affirm-card .n{font-size:11px;color:var(--ink-3);margin-top:14px}\n\n/* プロフィール */\n.avatar{\n  width:72px;height:72px;border-radius:50%;margin:0 auto 10px;\n  background:linear-gradient(135deg,var(--brand),#3f9d92);\n  display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:800;color:#fff;\n}\n.setting-row{display:flex;align-items:center;justify-content:space-between;padding:11px 0;border-bottom:1px solid var(--line);font-size:14px}\n.setting-row:last-child{border-bottom:none}\n.toggle{position:relative;width:44px;height:25px;border-radius:99px;background:var(--surface-2);border:1px solid var(--line);transition:.25s}\n.toggle::after{content:\"\";position:absolute;top:2px;left:2px;width:19px;height:19px;border-radius:50%;background:var(--ink-3);transition:.25s}\n.toggle.on{background:var(--c-routine);border-color:var(--c-routine)}\n.toggle.on::after{left:21px;background:#fff}\n</style>\n</head>\n<body>\n\n<!-- ============ ホーム(タイムスケジュール) ============ -->\n<section class=\"screen active\" id=\"scr-home\">\n  <header class=\"app\">\n    <div class=\"head-row\">\n      <div>\n        <div class=\"brand\">\n          <svg viewBox=\"0 0 64 64\" width=\"26\" height=\"26\" aria-hidden=\"true\">\n            <rect width=\"64\" height=\"64\" rx=\"16\" fill=\"var(--brand)\"/>\n            <g fill=\"none\" stroke=\"#fff\" stroke-width=\"3.5\" stroke-linecap=\"round\">\n              <circle cx=\"21\" cy=\"27\" r=\"9\"/>\n              <circle cx=\"16\" cy=\"36\" r=\"7.5\"/>\n              <circle cx=\"25\" cy=\"38\" r=\"5.5\"/>\n              <path d=\"M31 37h7\"/>\n              <circle cx=\"47\" cy=\"35\" r=\"9\"/>\n              <path d=\"M42.5 35l3.5 3.5 6.5-6.5\"/>\n            </g>\n          </svg>\n          <span class=\"logo-word\">ADHD<span class=\"o\">o</span></span>\n          <span class=\"lv-chip\" id=\"lv-chip\">Lv.1</span>\n        </div>\n        <div class=\"date\"><span id=\"home-date\"></span><span class=\"live-clock\" id=\"home-clock\"></span></div>\n      </div>\n      <div class=\"ach-mini\">\n        <div class=\"ach-mini-top\"><span>今日の達成率</span><b id=\"ach-pct\">0%</b></div>\n        <div class=\"ach-bar\"><div class=\"ach-fill\" id=\"ach-fill\"></div></div>\n        <div class=\"ach-meta\" id=\"ach-meta\"></div>\n      </div>\n    </div>\n\n    <div class=\"seg-tabs\">\n      <button id=\"tab-tl\" class=\"sel\">タイムライン</button>\n      <button id=\"tab-clock\">24Hグラフ</button>\n    </div>\n  </header>\n\n  <div id=\"view-clock\" style=\"display:none\">\n    <div class=\"clock-wrap\">\n      <svg id=\"clock\" viewBox=\"22 22 316 316\" aria-label=\"24時間スケジュール円グラフ\"></svg>\n      <div class=\"clock-center\">\n        <div class=\"day\" id=\"cc-day\"></div>\n        <div class=\"big-time\" id=\"cc-time\">--:--</div>\n        <div class=\"task-chip\" id=\"cc-chip\"><span class=\"dot\"></span><span id=\"cc-task\"></span></div>\n        <div class=\"remain\" id=\"cc-remain\"></div>\n      </div>\n      <div class=\"chart-tip\" id=\"chart-tip\"></div>\n    </div>\n    <div class=\"legend\" id=\"legend\"></div>\n  </div>\n\n  <div id=\"view-tl\">\n    <div id=\"carry-wrap\"></div>\n    <div class=\"tl-head\"><h2>タイムライン</h2><span>○で完了 / カードをタップで編集</span></div>\n    <div class=\"tl\" id=\"timeline\"></div>\n    <button class=\"fab\" id=\"fab-add\" aria-label=\"予定を追加\">+</button>\n  </div>\n</section>\n\n<!-- ============ 瞑想 ============ -->\n<section class=\"screen\" id=\"scr-meditate\">\n  <header class=\"app\"><h1>瞑想</h1><div class=\"date\">呼吸に意識を向けましょう</div></header>\n  <div class=\"panel\">\n    <div class=\"breath-stage\">\n      <div class=\"breath-circle\" id=\"breath-circle\"><span id=\"breath-label\">準備OK</span></div>\n      <div class=\"med-timer\" id=\"med-timer\">3:00</div>\n      <div class=\"med-presets\" id=\"med-presets\">\n        <button class=\"btn\" data-min=\"1\">1分</button>\n        <button class=\"btn sel\" data-min=\"3\">3分</button>\n        <button class=\"btn\" data-min=\"5\">5分</button>\n        <button class=\"btn\" data-min=\"10\">10分</button>\n      </div>\n      <div style=\"display:flex;gap:10px;margin-top:8px\">\n        <button class=\"btn primary\" id=\"med-start\">開始</button>\n        <button class=\"btn\" id=\"med-reset\">リセット</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"panel\">\n    <h3>やり方</h3>\n    <p style=\"font-size:13px;color:var(--ink-2)\">円が大きくなったら4秒かけて吸い、4秒止めて、8秒かけてゆっくり吐きます。考えごとが浮かんでも大丈夫。気づいたら呼吸に戻るだけでOK。</p>\n  </div>\n</section>\n\n<!-- ============ 日記 & アファメーション ============ -->\n<section class=\"screen\" id=\"scr-diary\">\n  <header class=\"app\"><h1>日記 & アファメーション</h1><div class=\"date\" id=\"diary-date\"></div></header>\n  <div class=\"affirm-card\">\n    <div class=\"q\" id=\"affirm-text\"></div>\n    <div class=\"n\" id=\"affirm-count\"></div>\n  </div>\n  <div style=\"display:flex;gap:10px;justify-content:center;margin-bottom:16px\">\n    <button class=\"btn primary\" id=\"affirm-next\">次の言葉</button>\n    <button class=\"btn\" id=\"affirm-add-toggle\">言葉を追加</button>\n  </div>\n  <div class=\"panel\" id=\"affirm-add-panel\" style=\"display:none\">\n    <h3>自分の言葉を追加</h3>\n    <input type=\"text\" id=\"affirm-input\" placeholder=\"例:私は一歩ずつ進んでいる\">\n    <div style=\"margin-top:10px;text-align:right\"><button class=\"btn\" id=\"affirm-add\">追加</button></div>\n  </div>\n  <div class=\"panel\">\n    <h3>今日のふりかえり</h3>\n    <textarea id=\"diary-text\" rows=\"5\" placeholder=\"今日できたこと、感じたことを自由に…\"></textarea>\n    <div style=\"margin-top:10px;text-align:right\"><button class=\"btn primary\" id=\"diary-save\">保存する</button></div>\n  </div>\n  <div class=\"panel\">\n    <h3>これまでの記録</h3>\n    <div id=\"diary-list\"><p style=\"font-size:13px;color:var(--ink-3)\">まだ記録がありません</p></div>\n  </div>\n</section>\n\n<!-- ============ マンスリー達成率カレンダー ============ -->\n<section class=\"screen\" id=\"scr-calendar\">\n  <header class=\"app\"><h1>マンスリー達成率</h1><div class=\"date\">色が濃い日ほど達成率が高い日</div></header>\n  <div class=\"cal-nav\">\n    <button class=\"btn\" id=\"cal-prev\">‹ 前月</button>\n    <b id=\"cal-title\"></b>\n    <button class=\"btn\" id=\"cal-next\">翌月 ›</button>\n  </div>\n  <div class=\"cal-grid\" id=\"cal-dow\"></div>\n  <div class=\"cal-grid\" id=\"cal-grid\" style=\"margin-top:6px\"></div>\n  <div class=\"panel\" style=\"margin-top:16px\">\n    <div class=\"ach-top\"><span>🔥 連続記録(1日休んでも切れません)</span><b id=\"cal-streak\">–</b></div>\n    <div class=\"ach-top\" style=\"margin-top:10px\"><span>直近7日の平均達成率</span><b id=\"cal-week\">–</b></div>\n  </div>\n  <div class=\"panel\">\n    <div class=\"ach-top\"><span>この月の平均達成率</span><b id=\"cal-avg\">–</b></div>\n    <p style=\"font-size:11px;color:var(--ink-3);margin-top:6px\">記録がある日だけで計算しています。タスクにチェックを付けた日が自動で記録されます。</p>\n  </div>\n</section>\n\n<!-- ============ プロフィール & 設定 ============ -->\n<section class=\"screen\" id=\"scr-profile\">\n  <header class=\"app\"><h1>プロフィール & 設定</h1></header>\n  <div class=\"panel\" style=\"text-align:center\">\n    <div class=\"avatar\" id=\"avatar\">A</div>\n    <input type=\"text\" id=\"profile-name\" placeholder=\"名前\" style=\"text-align:center;max-width:220px;margin:0 auto\">\n    <div style=\"max-width:260px;margin:14px auto 0;text-align:left\">\n      <div class=\"ach-top\" style=\"font-size:11px\"><span id=\"xp-level\" style=\"color:var(--brand);font-weight:800\">Lv.1</span><span id=\"xp-count\" style=\"color:var(--ink-3)\">0 XP</span></div>\n      <div class=\"xp-bar\"><div class=\"xp-fill\" id=\"xp-fill\" style=\"width:0%\"></div></div>\n      <p style=\"font-size:10.5px;color:var(--ink-3);margin-top:5px\">タスク完了で+10XP、集中タイマー完走で+20XP。100XPごとにレベルアップ</p>\n    </div>\n  </div>\n  <div class=\"panel\">\n    <h3>設定</h3>\n    <div class=\"setting-row\"><span>リマインダー通知</span><div class=\"toggle on\" data-key=\"notify\"></div></div>\n    <div class=\"setting-row\"><span>通知のテスト</span><button class=\"btn sm\" id=\"notify-test\">5秒後に通知</button></div>\n    <p id=\"notify-status\" style=\"font-size:11px;color:var(--ink-3);margin-top:8px;line-height:1.6\">ネイティブ通知: 未接続(Web版では通知は使えません。Expo版で有効になります)</p>\n    <div class=\"setting-row\"><span>サウンド</span><div class=\"toggle on\" data-key=\"sound\"></div></div>\n    <div class=\"setting-row\"><span>NOWへ自動スクロール</span><div class=\"toggle on\" data-key=\"autoscroll\"></div></div>\n    <div class=\"setting-row\"><span>スケジュールを初期状態に戻す</span><button class=\"btn\" id=\"reset-schedule\">リセット</button></div>\n  </div>\n  <div class=\"panel\">\n    <h3>スケジュールテンプレート</h3>\n    <p style=\"font-size:12.5px;color:var(--ink-2);line-height:1.7;margin-bottom:6px\">\n      今のスケジュールを保存して、いつでも呼び出せます(3つまで)。「平日用」「休日用」などに。\n    </p>\n    <div id=\"tpl-list\"></div>\n  </div>\n  <div class=\"panel\">\n    <h3>Googleカレンダー連携</h3>\n    <p style=\"font-size:12.5px;color:var(--ink-2);line-height:1.7;margin-bottom:12px\">\n      Googleカレンダーからエクスポートした予定ファイル(.ics)を読み込むと、今日の予定が\n      <span style=\"color:var(--c-meeting);font-weight:700\">ミーティング(黄緑)</span>としてタイムラインに追加されます。\n    </p>\n    <input type=\"file\" id=\"ics-file\" accept=\".ics,text/calendar\" style=\"display:none\">\n    <button class=\"btn primary\" id=\"ics-import\" style=\"width:100%\">.icsファイルを読み込む</button>\n    <p id=\"ics-result\" style=\"font-size:12px;color:var(--brand);margin-top:10px;display:none\"></p>\n    <p style=\"font-size:11px;color:var(--ink-3);line-height:1.7;margin-top:10px\">\n      ファイルの取得方法: Googleカレンダー(Web版)→ 設定 → インポート/エクスポート → エクスポート。\n      iPhone/iPadではダウンロードしたzipを開き、.icsを「ファイル」に保存してから選んでください。\n      ※終日予定は対象外、繰り返し予定は初回日程のみ対応\n    </p>\n  </div>\n  <div class=\"panel\">\n    <h3>1日の基本設定</h3>\n    <div class=\"setting-row\"><span>起床時間</span><input type=\"time\" value=\"06:30\" style=\"width:132px\"></div>\n    <div class=\"setting-row\"><span>就寝時間</span><input type=\"time\" value=\"23:00\" style=\"width:132px\"></div>\n  </div>\n  <p style=\"text-align:center;font-size:11px;color:var(--ink-3);margin-top:6px\">ADHDo v0.9</p>\n</section>\n\n<!-- ============ 予定エディタ ============ -->\n<div class=\"modal\" id=\"editor\">\n  <div class=\"sheet\">\n    <h3 id=\"ed-heading\">予定を編集</h3>\n    <div class=\"f-label\">タイトル</div>\n    <input type=\"text\" id=\"ed-name\" placeholder=\"例:読書\">\n    <div class=\"f-label\">カテゴリ</div>\n    <div class=\"cat-chips\" id=\"ed-cats\"></div>\n    <div class=\"f-label\">時間(開始 → 終了)</div>\n    <div class=\"time-row\">\n      <input type=\"time\" id=\"ed-start\" value=\"09:00\">\n      <span style=\"color:var(--ink-3)\">→</span>\n      <input type=\"time\" id=\"ed-end\" value=\"10:00\">\n    </div>\n    <div class=\"f-label\">サブ項目(任意)</div>\n    <div id=\"ed-subs\"></div>\n    <button class=\"btn\" id=\"ed-addsub\" style=\"width:100%\">+ サブ項目を追加</button>\n    <p class=\"ed-error\" id=\"ed-error\"></p>\n    <div class=\"sheet-actions\">\n      <button class=\"btn danger\" id=\"ed-delete\">削除</button>\n      <button class=\"btn\" id=\"ed-cancel\">キャンセル</button>\n      <button class=\"btn primary\" id=\"ed-save\">保存</button>\n    </div>\n  </div>\n</div>\n\n<!-- ============ 集中タイマー ============ -->\n<div class=\"modal center\" id=\"focus\">\n  <div class=\"focus-box\">\n    <div class=\"focus-phase\" id=\"focus-phase\">FOCUS</div>\n    <div class=\"focus-task-name\" id=\"focus-task\"></div>\n    <div class=\"focus-time\" id=\"focus-time\">25:00</div>\n    <p class=\"focus-hint\" id=\"focus-hint\">まずは始めるだけでOK。終わったら5分休憩</p>\n    <div class=\"focus-presets\" id=\"focus-presets\">\n      <button class=\"btn sm\" data-fmin=\"15\">15分</button>\n      <button class=\"btn sm sel\" data-fmin=\"25\">25分</button>\n      <button class=\"btn sm\" data-fmin=\"45\">45分</button>\n    </div>\n    <div class=\"focus-btn-row\">\n      <button class=\"btn primary\" id=\"focus-start\">開始</button>\n      <button class=\"btn\" id=\"focus-close\">閉じる</button>\n    </div>\n  </div>\n</div>\n\n<!-- ============ フッターナビ ============ -->\n<nav class=\"footer\">\n  <button data-scr=\"home\" class=\"active\">\n    <svg viewBox=\"0 0 24 24\"><path d=\"M3 10.5 12 3l9 7.5\"/><path d=\"M5 9.5V21h14V9.5\"/><path d=\"M9.5 21v-6h5v6\"/></svg>\n    ホーム\n  </button>\n  <button data-scr=\"meditate\">\n    <svg viewBox=\"0 0 24 24\"><circle cx=\"12\" cy=\"5.5\" r=\"2.2\"/><path d=\"M12 8v4.5\"/><path d=\"M6 20c1-4 3.5-6 6-6s5 2 6 6\"/><path d=\"M4.5 15.5c2 .8 3.5 2 4 4.5M19.5 15.5c-2 .8-3.5 2-4 4.5\"/></svg>\n    瞑想\n  </button>\n  <button data-scr=\"diary\">\n    <svg viewBox=\"0 0 24 24\"><path d=\"M5 4h11a2 2 0 0 1 2 2v14H7a2 2 0 0 1-2-2V4z\"/><path d=\"M5 4a2 2 0 0 1 2-2h11v16\"/><path d=\"M9 8h6M9 12h6\"/></svg>\n    日記\n  </button>\n  <button data-scr=\"calendar\">\n    <svg viewBox=\"0 0 24 24\"><rect x=\"3.5\" y=\"5\" width=\"17\" height=\"16\" rx=\"2.5\"/><path d=\"M3.5 10h17M8 2.5V6M16 2.5V6\"/><path d=\"M7.5 14h2M11 14h2M14.5 14h2M7.5 17.5h2M11 17.5h2\"/></svg>\n    カレンダー\n  </button>\n  <button data-scr=\"profile\">\n    <svg viewBox=\"0 0 24 24\"><circle cx=\"12\" cy=\"8\" r=\"3.5\"/><path d=\"M5 20c.8-3.8 3.6-5.5 7-5.5s6.2 1.7 7 5.5\"/></svg>\n    プロフィール\n  </button>\n</nav>\n\n<script>\n/* ================= データ ================= */\nconst CATS = {\n  workout:{name:'筋トレ',    color:'var(--c-workout)', hex:'#f4526a', icon:'💪'},\n  work:   {name:'Work',      color:'var(--c-work)',    hex:'#4a8df8', icon:'💻'},\n  meal:   {name:'食事',      color:'var(--c-meal)',    hex:'#d97706', icon:'🍙'},\n  sleep:  {name:'睡眠',      color:'var(--c-sleep)',   hex:'#9d7bf5', icon:'🌙'},\n  routine:{name:'ルーティン', color:'var(--c-routine)', hex:'#0da06f', icon:'🌿'},\n  meeting:{name:'ミーティング', color:'var(--c-meeting)', hex:'#84a31c', icon:'🤝'},\n};\n\n// start/end は 0:00 からの分。end < start は日付をまたぐ(睡眠)\nconst DEFAULT_SCHEDULE = [\n  {id:'am-routine', cat:'routine', title:'モーニングルーティン', start:390,  end:450, subs:[\n    {name:'起床・水分補給', start:390, end:405},\n    {name:'瞑想',           start:405, end:425},\n    {name:'シャワー・身支度', start:425, end:450},\n  ]},\n  {id:'breakfast', cat:'meal', title:'朝食', start:450, end:480},\n  {id:'workout', cat:'workout', title:'筋トレ', start:480, end:540, subs:[\n    {name:'ウォームアップ', start:480, end:490},\n    {name:'ベンチプレス',   start:490, end:510},\n    {name:'スクワット',     start:510, end:530},\n    {name:'クールダウン',   start:530, end:540},\n  ]},\n  {id:'work-am', cat:'work', title:'Work(午前)', start:540, end:720, subs:[\n    {name:'メール・タスク整理', start:540, end:570},\n    {name:'集中タスク',        start:570, end:690},\n    {name:'ミーティング',      start:690, end:720},\n  ]},\n  {id:'lunch', cat:'meal', title:'昼食・休憩', start:720, end:780},\n  {id:'work-pm', cat:'work', title:'Work(午後)', start:780, end:1080, subs:[\n    {name:'集中タスク',           start:780,  end:900},\n    {name:'休憩・軽いストレッチ',  start:900,  end:915},\n    {name:'タスク処理',           start:915,  end:1050},\n    {name:'振り返り・明日の計画',  start:1050, end:1080},\n  ]},\n  {id:'dinner', cat:'meal', title:'夕食', start:1080, end:1140},\n  {id:'ev-routine', cat:'routine', title:'イブニングルーティン', start:1140, end:1290, subs:[\n    {name:'散歩',     start:1140, end:1180},\n    {name:'自由時間', start:1180, end:1260},\n    {name:'片付け',   start:1260, end:1290},\n  ]},\n  {id:'night-routine', cat:'routine', title:'ナイトルーティン', start:1290, end:1380, subs:[\n    {name:'日記',     start:1290, end:1320},\n    {name:'瞑想',     start:1320, end:1340},\n    {name:'ストレッチ', start:1340, end:1360},\n    {name:'就寝準備', start:1360, end:1380},\n  ]},\n  {id:'sleep', cat:'sleep', title:'睡眠', start:1380, end:390},\n];\n\n/* ================= ユーティリティ ================= */\nconst $ = s => document.querySelector(s);\nconst esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;');\nconst fmt = m => `${String(Math.floor((m%1440)/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`;\nconst dur = e => (e.end - e.start + 1440) % 1440;\nconst nowMin = () => { const d = new Date(); return d.getHours()*60 + d.getMinutes(); };\nconst isActive = (e,n) => e.start < e.end ? (n >= e.start && n < e.end) : (n >= e.start || n < e.end);\nconst isPast = (e,n) => e.start < e.end && n >= e.end;\nconst durLabel = m => m >= 60 ? (m%60 ? `${Math.floor(m/60)}時間${m%60}分` : `${Math.floor(m/60)}時間`) : `${m}分`;\nconst store = {\n  get(k,f){ try{ return JSON.parse(localStorage.getItem('adhdo.'+k)) ?? f }catch{ return f } },\n  set(k,v){\n    try{ localStorage.setItem('adhdo.'+k, JSON.stringify(v)) }catch{}\n    // ネイティブアプリ(Expo/WebView)内ではAsyncStorageにもミラー保存\n    try{ window.ReactNativeWebView && window.ReactNativeWebView.postMessage(JSON.stringify({type:'kv', key:'adhdo.'+k, value:JSON.stringify(v)})) }catch{}\n  },\n};\n\n// ネイティブ側からの状態通知を受けるフック\nwindow.__notifySet = function(n){\n  const el = document.querySelector('#notify-status');\n  if(!el) return;\n  if(n === -1){ el.textContent = 'ネイティブ通知: 権限がありません。iPadの設定→通知→Expo Goで許可してください'; el.style.color = 'var(--c-workout)'; }\n  else if(n === -2){ el.textContent = 'ネイティブ通知: エラーが発生しました'; el.style.color = 'var(--c-workout)'; }\n  else if(n === 0){ el.textContent = 'ネイティブ通知: 接続OK(通知OFF設定のためセットなし)'; el.style.color = ''; }\n  else { el.textContent = `ネイティブ通知: 接続OK ✓ 毎日${n}件の通知をセット済み`; el.style.color = 'var(--brand)'; }\n};\nwindow.__notifyTest = function(ok){\n  const el = document.querySelector('#notify-status');\n  if(!el) return;\n  el.textContent = ok\n    ? 'テスト通知を予約しました。5秒待ってください(アプリを閉じていてもOK)'\n    : '通知の権限がありません。iPadの設定→通知→Expo Goで許可してください';\n  el.style.color = ok ? 'var(--brand)' : 'var(--c-workout)';\n};\n\n// ネイティブアプリに通知スケジュールを送る(ブラウザでは何もしない)\nfunction syncNative(){\n  try{\n    if(!window.ReactNativeWebView) return;\n    window.ReactNativeWebView.postMessage(JSON.stringify({\n      type: 'schedule',\n      notify: store.get('set.notify', true),\n      events: SCHEDULE.filter(e => e.cat !== 'sleep').map(e => ({\n        title: e.title, start: e.start, end: e.end,\n        firstSub: e.subs && e.subs.length ? e.subs[0].name : null,\n      })),\n    }));\n  }catch{}\n}\n\n// 編集したスケジュールは端末に保存。なければ初期スケジュール\nlet SCHEDULE = store.get('schedule', null) || JSON.parse(JSON.stringify(DEFAULT_SCHEDULE));\nfunction persistSchedule(){\n  SCHEDULE.sort((a,b) => a.start - b.start);\n  store.set('schedule', SCHEDULE);\n  refreshHome();\n  renderLegend();\n  syncNative();\n}\n\n// 完了チェック(達成は自動判定せず、自分でチェックする。日付が変わるとリセット)\nconst todayKey = () => { const d = new Date(); return `${d.getFullYear()}-${d.getMonth()+1}-${d.getDate()}`; };\nlet doneData = store.get('done', null);\nif(!doneData || doneData.date !== todayKey()) doneData = {date: todayKey(), items: {}, skips: {}};\ndoneData.skips = doneData.skips || {};\nconst isDone = key => doneData.items[key] === true;\nconst skipStateOf = id => doneData.skips[id]; // 'skip' | 'carry' | undefined\nfunction toggleDone(key, clickPos){\n  if(doneData.items[key]){\n    delete doneData.items[key];\n    addXP(-10);\n  }else{\n    doneData.items[key] = true;\n    addXP(10);\n    if(clickPos) confettiBurst(clickPos.x, clickPos.y);\n  }\n  store.set('done', doneData);\n  const before100 = $('#ach-pct').textContent;\n  refreshHome();\n  if($('#ach-pct').textContent === '100%' && before100 !== '100%'){\n    confettiBurst(innerWidth/2, innerHeight/3, 36);\n  }\n}\n\n/* ================= 許す仕組み(スキップ / 明日へ持ち越し) ================= */\nconst tomorrowKey = () => { const d = new Date(Date.now() + 86400000); return `${d.getFullYear()}-${d.getMonth()+1}-${d.getDate()}`; };\nfunction setSkip(id, mode){ // mode: 'skip' | 'carry' | null(解除)\n  if(mode) doneData.skips[id] = mode;\n  else delete doneData.skips[id];\n  store.set('done', doneData);\n  refreshHome();\n}\nfunction sendToTomorrow(ev){\n  let carry = store.get('carry', null);\n  if(!carry || carry.date !== tomorrowKey()) carry = {date: tomorrowKey(), items: []};\n  carry.items.push({title: ev.title, cat: ev.cat, done: false});\n  store.set('carry', carry);\n  setSkip(ev.id, 'carry');\n}\nfunction renderCarry(){\n  const wrap = $('#carry-wrap');\n  const carry = store.get('carry', null);\n  if(!carry || carry.date !== todayKey() || !carry.items.length){ wrap.innerHTML = ''; return; }\n  wrap.innerHTML = `<div class=\"carry-panel\"><h4>📦 昨日からの持ち越し</h4>${carry.items.map((it, i) => `\n    <div class=\"sub${it.done ? ' done' : ''}\" style=\"padding:4px 0\">\n      <button class=\"s-check${it.done ? ' on' : ''}\" data-carry-i=\"${i}\">${it.done ? '✓' : ''}</button>\n      <span class=\"s-name\">${CATS[it.cat] ? CATS[it.cat].icon + ' ' : ''}${esc(it.title)}</span>\n    </div>`).join('')}</div>`;\n}\n\n/* ================= XP・レベル ================= */\nfunction addXP(n){\n  const xp = Math.max(0, store.get('xp', 0) + n);\n  store.set('xp', xp);\n  renderLevel();\n}\nfunction renderLevel(){\n  const xp = store.get('xp', 0);\n  const lv = Math.floor(xp / 100) + 1;\n  $('#lv-chip').textContent = 'Lv.' + lv;\n  $('#xp-level').textContent = 'Lv.' + lv;\n  $('#xp-count').textContent = `${xp} XP(次のレベルまで ${100 - xp % 100} XP)`;\n  $('#xp-fill').style.width = (xp % 100) + '%';\n}\n\n/* ================= 紙吹雪 ================= */\nfunction confettiBurst(x, y, count = 14){\n  const colors = ['#f4526a','#4a8df8','#d97706','#9d7bf5','#0da06f','#84a31c','#7bc5ba'];\n  for(let i = 0; i < count; i++){\n    const el = document.createElement('div');\n    el.className = 'confetti';\n    el.style.left = x + 'px';\n    el.style.top = y + 'px';\n    el.style.background = colors[i % colors.length];\n    document.body.appendChild(el);\n    const ang = Math.random() * Math.PI * 2;\n    const dist = 40 + Math.random() * 70;\n    el.animate([\n      {transform: 'translate(0,0) rotate(0deg) scale(1)', opacity: 1},\n      {transform: `translate(${Math.cos(ang)*dist}px,${Math.sin(ang)*dist - 30}px) rotate(${Math.random()*540-270}deg) scale(.4)`, opacity: 0},\n    ], {duration: 650 + Math.random() * 350, easing: 'cubic-bezier(.15,.6,.4,1)'}).onfinish = () => el.remove();\n  }\n}\n\n/* ================= タイムライン ================= */\nfunction renderTimeline(){\n  const n = nowMin();\n  const tl = $('#timeline');\n  tl.innerHTML = '';\n  for(const e of SCHEDULE){\n    const cat = CATS[e.cat];\n    const checkable = e.cat !== 'sleep';\n    const hasSubs = !!(e.subs && e.subs.length);\n    const evDone = checkable && !hasSubs && isDone(e.id);\n    const subDoneCount = hasSubs ? e.subs.filter((s,i) => isDone(e.id + '/' + i)).length : 0;\n\n    const skipState = checkable ? skipStateOf(e.id) : null;\n    const active = isActive(e,n), past = !active && isPast(e,n);\n    const fullyDone = checkable && (hasSubs ? subDoneCount === e.subs.length : evDone);\n\n    const item = document.createElement('div');\n    item.className = 'tl-item' + (active ? ' now' : past ? ' past' : '') + (evDone ? ' checked' : '') + (skipState ? ' skipped' : '');\n    item.dataset.id = e.id;\n    item.style.setProperty('--cat', cat.color);\n\n    const elapsed = (n - e.start + 1440) % 1440;\n    const pct = Math.min(100, Math.round(elapsed / dur(e) * 100));\n    const remain = dur(e) - elapsed;\n\n    // スキップ/持ち越しのクイック操作(未完了カードに表示)\n    let quick = '';\n    if(skipState){\n      quick = `<div class=\"quick\"><button data-unskip=\"${e.id}\">元に戻す</button></div>`;\n    }else if(checkable && !fullyDone){\n      quick = `<div class=\"quick\"><button data-skip=\"${e.id}\">今日はスキップ</button><button data-carry=\"${e.id}\">明日へ送る</button></div>`;\n    }\n\n    item.innerHTML = `\n      <div class=\"tl-time\">${fmt(e.start)}</div>\n      <div class=\"tl-node\"></div>\n      <div class=\"tl-card\">\n        <div class=\"row1\">\n          ${checkable && !hasSubs && !skipState ? `<button class=\"ev-check${evDone ? ' on' : ''}\" data-key=\"${e.id}\" aria-label=\"完了\">${evDone ? '✓' : ''}</button>` : ''}\n          <span class=\"title\">${cat.icon} ${esc(e.title)}</span>\n          ${hasSubs && checkable && !skipState ? `<span class=\"sub-count\">${subDoneCount}/${e.subs.length}</span>` : ''}\n          ${skipState ? `<span class=\"skip-badge\">${skipState === 'carry' ? '📦 明日へ' : 'スキップ中'}</span>` : ''}\n          <span class=\"now-badge\">NOW</span>\n          ${skipState ? '' : '<span class=\"cat-tag\">' + cat.name + '</span>'}\n        </div>\n        <div class=\"range\">${fmt(e.start)} – ${fmt(e.end)} ・ ${durLabel(dur(e))}</div>\n        ${hasSubs && !skipState ? `<div class=\"subs\">${e.subs.map((s,si) => {\n          const key = e.id + '/' + si;\n          const sd = checkable && isDone(key);\n          const cls = (isActive(s,n) && active ? ' active' : '') + (sd ? ' done' : '');\n          const lead = checkable\n            ? `<button class=\"s-check${sd ? ' on' : ''}\" data-key=\"${key}\" aria-label=\"完了\">${sd ? '✓' : ''}</button>`\n            : '<span class=\"s-dot\"></span>';\n          return `<div class=\"sub${cls}\">${lead}<span class=\"s-name\">${esc(s.name)}</span><span class=\"s-time\">${fmt(s.start)} – ${fmt(s.end)}</span></div>`;\n        }).join('')}</div>` : ''}\n        <div class=\"now-progress\">\n          <div class=\"bar\"><div class=\"fill\" style=\"width:${pct}%\"></div></div>\n          <div class=\"meta\"><span>${pct}% 経過</span><span>あと ${durLabel(remain)}</span></div>\n          ${checkable ? `<button class=\"focus-open\" data-focus=\"${esc(e.title)}\">▶ 集中タイマーで始める</button>` : ''}\n        </div>\n        ${quick}\n      </div>`;\n    tl.appendChild(item);\n  }\n  renderCarry();\n}\n\nfunction scrollToNow(smooth=true){\n  if(!store.get('set.autoscroll', true)) return;\n  const el = document.querySelector('.tl-item.now');\n  if(el) el.scrollIntoView({behavior: smooth ? 'smooth' : 'auto', block:'center'});\n}\n\n/* ================= 24hチャート ================= */\nconst C = 180, R_OUT = 132, R_IN = 100;\nconst polar = (r,deg) => { const a = (deg-90)*Math.PI/180; return [C + r*Math.cos(a), C + r*Math.sin(a)]; };\nfunction arcPath(rO,rI,a0,a1){\n  const large = (a1-a0) > 180 ? 1 : 0;\n  const [x0,y0] = polar(rO,a0), [x1,y1] = polar(rO,a1);\n  const [x2,y2] = polar(rI,a1), [x3,y3] = polar(rI,a0);\n  return `M${x0.toFixed(2)} ${y0.toFixed(2)} A${rO} ${rO} 0 ${large} 1 ${x1.toFixed(2)} ${y1.toFixed(2)} L${x2.toFixed(2)} ${y2.toFixed(2)} A${rI} ${rI} 0 ${large} 0 ${x3.toFixed(2)} ${y3.toFixed(2)} Z`;\n}\nconst toDeg = m => m/1440*360;\n\nfunction chartSegments(){\n  // 日付またぎを分割してチャート用セグメントに\n  const segs = [];\n  for(const e of SCHEDULE){\n    if(e.start < e.end) segs.push({...e, s:e.start, t:e.end});\n    else { segs.push({...e, s:e.start, t:1440}); segs.push({...e, s:0, t:e.end, wrapped:true}); }\n  }\n  return segs;\n}\n\nfunction renderClock(){\n  const n = nowMin();\n  const svg = $('#clock');\n  const GAP = 0.7; // セグメント間の角度ギャップ(≈2px)\n  let html = '';\n\n  // 背景リング\n  html += `<circle cx=\"${C}\" cy=\"${C}\" r=\"${(R_OUT+R_IN)/2}\" fill=\"none\" stroke=\"var(--surface-2)\" stroke-width=\"${R_OUT-R_IN}\"/>`;\n\n  // グロー用フィルタ\n  html += `<defs>`;\n  for(const [k,c] of Object.entries(CATS)){\n    html += `<filter id=\"glow-${k}\" x=\"-40%\" y=\"-40%\" width=\"180%\" height=\"180%\">\n      <feDropShadow dx=\"0\" dy=\"0\" stdDeviation=\"5\" flood-color=\"${c.hex}\" flood-opacity=\"0.7\"/></filter>`;\n  }\n  html += `</defs>`;\n\n  // セグメント\n  const segs = chartSegments();\n  for(const sg of segs){\n    const a0 = toDeg(sg.s) + GAP/2, a1 = toDeg(sg.t) - GAP/2;\n    if(a1 <= a0) continue;\n    const active = isActive(sg, n);\n    html += `<path class=\"seg${!active && sg.t <= n ? ' dim' : ''}\" data-id=\"${sg.id}\"\n      d=\"${arcPath(active ? R_OUT+5 : R_OUT, active ? R_IN-2 : R_IN, a0, a1)}\"\n      fill=\"${CATS[sg.cat].hex}\" ${active ? `filter=\"url(#glow-${sg.cat})\"` : ''}/>`;\n  }\n\n  // セグメント上のアイコンと時間ラベル\n  for(const sg of segs){\n    if(sg.wrapped) continue;\n    const span = dur(sg);\n    const midDeg = toDeg((sg.start + span/2) % 1440);\n    const rMid = (R_OUT + R_IN)/2;\n    if(span >= 45){\n      const [ix,iy] = polar(rMid, midDeg);\n      html += `<text x=\"${ix}\" y=\"${iy}\" font-size=\"14\" text-anchor=\"middle\" dominant-baseline=\"central\" pointer-events=\"none\">${CATS[sg.cat].icon}</text>`;\n    }\n    if(span >= 120){\n      const [lx,ly] = polar(R_OUT + 14, midDeg);\n      html += `<text x=\"${lx}\" y=\"${ly}\" font-size=\"10\" font-weight=\"700\" fill=\"var(--ink-2)\" text-anchor=\"middle\" dominant-baseline=\"central\" pointer-events=\"none\">${(span/60).toFixed(span%60?1:0)}h</text>`;\n    }\n  }\n\n  // 時間目盛り(1時間ごと・6時間ごとに強調+ラベル)\n  for(let h=0; h<24; h++){\n    const deg = toDeg(h*60);\n    const major = h % 6 === 0;\n    const [x0,y0] = polar(R_IN - 6, deg), [x1,y1] = polar(R_IN - (major ? 14 : 10), deg);\n    html += `<line x1=\"${x0}\" y1=\"${y0}\" x2=\"${x1}\" y2=\"${y1}\" stroke=\"${major ? 'var(--ink-3)' : 'var(--line)'}\" stroke-width=\"${major ? 2 : 1}\"/>`;\n    if(major){\n      const [tx,ty] = polar(R_IN - 24, deg);\n      html += `<text x=\"${tx}\" y=\"${ty}\" font-size=\"10\" fill=\"var(--ink-3)\" text-anchor=\"middle\" dominant-baseline=\"central\">${h}</text>`;\n    }\n  }\n\n  // 現在時刻の針\n  const nd = toDeg(n);\n  const [nx0,ny0] = polar(R_IN - 2, nd), [nx1,ny1] = polar(R_OUT + 9, nd);\n  html += `<line x1=\"${nx0}\" y1=\"${ny0}\" x2=\"${nx1}\" y2=\"${ny1}\" stroke=\"#fff\" stroke-width=\"2.5\" stroke-linecap=\"round\" opacity=\"0.95\"/>`;\n  html += `<circle cx=\"${nx1}\" cy=\"${ny1}\" r=\"4.5\" fill=\"#fff\"/>`;\n  const cur = SCHEDULE.find(e => isActive(e, n));\n  if(cur) html += `<circle cx=\"${nx1}\" cy=\"${ny1}\" r=\"8\" fill=\"none\" stroke=\"${CATS[cur.cat].hex}\" stroke-width=\"2\"><animate attributeName=\"r\" values=\"6;11;6\" dur=\"2s\" repeatCount=\"indefinite\"/><animate attributeName=\"opacity\" values=\"1;0;1\" dur=\"2s\" repeatCount=\"indefinite\"/></circle>`;\n\n  svg.innerHTML = html;\n\n  // 中央表示\n  const d = new Date();\n  $('#cc-time').textContent = fmt(n);\n  $('#cc-day').textContent = `${d.getMonth()+1}/${d.getDate()} ${'日月火水木金土'[d.getDay()]}曜日`;\n  if(cur){\n    const c = CATS[cur.cat];\n    $('#cc-chip').querySelector('.dot').style.background = c.hex;\n    $('#cc-task').textContent = cur.title;\n    const remain = dur(cur) - ((n - cur.start + 1440) % 1440);\n    $('#cc-remain').textContent = `${fmt(cur.end)} まで・あと${durLabel(remain)}`;\n  }\n\n  // タップで詳細&タイムラインへ\n  svg.querySelectorAll('.seg').forEach(p => p.addEventListener('click', ev => {\n    ev.stopPropagation();\n    const e = SCHEDULE.find(x => x.id === p.dataset.id);\n    const tip = $('#chart-tip');\n    tip.innerHTML = `<b style=\"color:${CATS[e.cat].hex}\">${CATS[e.cat].icon} ${esc(e.title)}</b> <span class=\"t\">${fmt(e.start)}–${fmt(e.end)} (${durLabel(dur(e))})</span>`;\n    tip.classList.add('show');\n    clearTimeout(tip._t);\n    tip._t = setTimeout(() => tip.classList.remove('show'), 2200);\n    // 少し見せてからタイムラインに切り替えて該当カードへ\n    setTimeout(() => {\n      setView('tl');\n      const card = document.querySelector(`.tl-item[data-id=\"${e.id}\"]`);\n      if(card){\n        card.scrollIntoView({behavior:'smooth', block:'center'});\n        card.classList.add('flash');\n        setTimeout(() => card.classList.remove('flash'), 1600);\n      }\n    }, 650);\n  }));\n}\n\nfunction renderLegend(){\n  const totals = {};\n  for(const e of SCHEDULE) totals[e.cat] = (totals[e.cat] || 0) + dur(e);\n  $('#legend').innerHTML = Object.entries(CATS).filter(([k]) => totals[k]).map(([k,c]) =>\n    `<span class=\"item\"><span class=\"dot\" style=\"background:${c.hex}\"></span>${c.name} <b>${(totals[k]/60).toFixed(totals[k]%60?1:0)}h</b></span>`\n  ).join('');\n}\n\n/* ================= ナビゲーション ================= */\ndocument.querySelectorAll('nav.footer button').forEach(btn => {\n  btn.addEventListener('click', () => {\n    document.querySelectorAll('nav.footer button').forEach(b => b.classList.toggle('active', b === btn));\n    document.querySelectorAll('.screen').forEach(s => s.classList.toggle('active', s.id === 'scr-' + btn.dataset.scr));\n    if(btn.dataset.scr === 'home'){ refreshHome(); setTimeout(() => scrollToNow(), 60); }\n    else if(btn.dataset.scr === 'calendar'){ renderCalendar(); window.scrollTo(0,0); }\n    else window.scrollTo(0,0);\n  });\n});\n\n/* ================= 瞑想 ================= */\nlet medTotal = 180, medLeft = 180, medTimer = null, breathTimer = null;\nconst medFmt = s => `${Math.floor(s/60)}:${String(s%60).padStart(2,'0')}`;\nfunction medRender(){ $('#med-timer').textContent = medFmt(medLeft); }\nfunction breathLoop(){\n  const c = $('#breath-circle'), l = $('#breath-label');\n  const phases = [['吸って…',4000,'inhale'],['止めて',4000,'inhale'],['吐いて…',8000,'exhale']];\n  let i = 0;\n  const step = () => {\n    const [label,ms,cls] = phases[i % 3];\n    l.textContent = label;\n    c.classList.remove('inhale','exhale');\n    if(cls) c.classList.add(cls);\n    i++;\n    breathTimer = setTimeout(step, ms);\n  };\n  step();\n}\n$('#med-start').addEventListener('click', () => {\n  if(medTimer){ // 一時停止\n    clearInterval(medTimer); clearTimeout(breathTimer); medTimer = null;\n    $('#med-start').textContent = '再開';\n    $('#breath-circle').classList.remove('inhale','exhale');\n    $('#breath-label').textContent = '一時停止中';\n    return;\n  }\n  $('#med-start').textContent = '一時停止';\n  breathLoop();\n  medTimer = setInterval(() => {\n    medLeft--;\n    medRender();\n    if(medLeft <= 0){\n      clearInterval(medTimer); clearTimeout(breathTimer); medTimer = null;\n      $('#breath-circle').classList.remove('inhale','exhale');\n      $('#breath-label').textContent = 'おつかれさま 🌿';\n      $('#med-start').textContent = '開始';\n      medLeft = medTotal;\n      setTimeout(medRender, 1500);\n    }\n  }, 1000);\n});\n$('#med-reset').addEventListener('click', () => {\n  clearInterval(medTimer); clearTimeout(breathTimer); medTimer = null;\n  medLeft = medTotal; medRender();\n  $('#med-start').textContent = '開始';\n  $('#breath-circle').classList.remove('inhale','exhale');\n  $('#breath-label').textContent = '準備OK';\n});\n$('#med-presets').addEventListener('click', e => {\n  const b = e.target.closest('button'); if(!b) return;\n  document.querySelectorAll('#med-presets .btn').forEach(x => x.classList.toggle('sel', x === b));\n  medTotal = medLeft = +b.dataset.min * 60; medRender();\n});\n\n/* ================= 日記 ================= */\nfunction renderDiary(){\n  const list = store.get('diary', []);\n  $('#diary-list').innerHTML = list.length\n    ? list.map((e,i) => `<div class=\"diary-entry\"><div class=\"d\"><span>${e.date}</span><button data-i=\"${i}\">削除</button></div><p>${e.text.replace(/</g,'&lt;')}</p></div>`).join('')\n    : '<p style=\"font-size:13px;color:var(--ink-3)\">まだ記録がありません</p>';\n}\n$('#diary-save').addEventListener('click', () => {\n  const t = $('#diary-text').value.trim(); if(!t) return;\n  const d = new Date();\n  const list = store.get('diary', []);\n  list.unshift({date:`${d.getFullYear()}/${d.getMonth()+1}/${d.getDate()} ${fmt(nowMin())}`, text:t});\n  store.set('diary', list);\n  $('#diary-text').value = '';\n  renderDiary();\n});\n$('#diary-list').addEventListener('click', e => {\n  const b = e.target.closest('button'); if(!b) return;\n  const list = store.get('diary', []);\n  list.splice(+b.dataset.i, 1);\n  store.set('diary', list);\n  renderDiary();\n});\n\n/* ================= アファメーション ================= */\nconst DEFAULT_AFFIRMS = [\n  '私は今、やるべきことに集中できる',\n  '小さな一歩も、確かな前進だ',\n  '完璧じゃなくていい。続けることが大事',\n  '私の脳はユニークで、それは強みだ',\n  '休むことも、前に進むための行動だ',\n  '昨日の自分より、少しだけ良くなればいい',\n];\nlet affirmIdx = 0;\nfunction affirms(){ return [...DEFAULT_AFFIRMS, ...store.get('affirms', [])]; }\nfunction renderAffirm(){\n  const a = affirms();\n  $('#affirm-text').textContent = a[affirmIdx % a.length];\n  $('#affirm-count').textContent = `${affirmIdx % a.length + 1} / ${a.length}`;\n}\n$('#affirm-next').addEventListener('click', () => { affirmIdx++; renderAffirm(); });\n$('#affirm-add-toggle').addEventListener('click', () => {\n  const p = $('#affirm-add-panel');\n  p.style.display = p.style.display === 'none' ? '' : 'none';\n});\n$('#affirm-add').addEventListener('click', () => {\n  const v = $('#affirm-input').value.trim(); if(!v) return;\n  const list = store.get('affirms', []);\n  list.push(v); store.set('affirms', list);\n  $('#affirm-input').value = '';\n  affirmIdx = affirms().length - 1;\n  renderAffirm();\n});\n\n/* ================= プロフィール ================= */\n$('#profile-name').value = store.get('name', '');\nif(store.get('name','')) $('#avatar').textContent = store.get('name','A')[0];\n$('#profile-name').addEventListener('input', e => {\n  store.set('name', e.target.value);\n  $('#avatar').textContent = (e.target.value || 'A')[0];\n});\ndocument.querySelectorAll('.toggle').forEach(t => {\n  const k = 'set.' + t.dataset.key;\n  t.classList.toggle('on', store.get(k, true));\n  t.addEventListener('click', () => {\n    t.classList.toggle('on');\n    store.set(k, t.classList.contains('on'));\n    if(t.dataset.key === 'notify') syncNative(); // 通知ON/OFFを即ネイティブに反映\n  });\n});\n\n/* ================= 予定エディタ ================= */\nconst toMin = s => { const [h,m] = s.split(':').map(Number); return h*60 + m; };\nlet editing = null;\nlet edCat = 'routine';\n\nfunction renderCatChips(){\n  $('#ed-cats').innerHTML = Object.entries(CATS).map(([k,c]) =>\n    `<button class=\"cat-chip${k===edCat?' sel':''}\" data-cat=\"${k}\" ${k===edCat?`style=\"background:${c.hex}\"`:''}>${c.icon} ${c.name}</button>`\n  ).join('');\n}\n$('#ed-cats').addEventListener('click', e => {\n  const b = e.target.closest('.cat-chip'); if(!b) return;\n  edCat = b.dataset.cat;\n  renderCatChips();\n});\n\nfunction addSubRow(sub){\n  const row = document.createElement('div');\n  row.className = 'sub-edit';\n  row.innerHTML = `\n    <input type=\"text\" class=\"se-name\" placeholder=\"サブ項目名\" value=\"${sub ? esc(sub.name) : ''}\">\n    <input type=\"time\" class=\"se-start\" value=\"${sub ? fmt(sub.start) : $('#ed-start').value}\">\n    <input type=\"time\" class=\"se-end\" value=\"${sub ? fmt(sub.end) : $('#ed-end').value}\">\n    <button class=\"sub-del\" aria-label=\"削除\">×</button>`;\n  row.querySelector('.sub-del').addEventListener('click', () => row.remove());\n  $('#ed-subs').appendChild(row);\n}\n$('#ed-addsub').addEventListener('click', () => addSubRow(null));\n\nfunction openEditor(ev){\n  editing = ev;\n  $('#ed-heading').textContent = ev ? '予定を編集' : '予定を追加';\n  $('#ed-name').value = ev ? ev.title : '';\n  edCat = ev ? ev.cat : 'routine';\n  renderCatChips();\n  $('#ed-start').value = ev ? fmt(ev.start) : '09:00';\n  $('#ed-end').value = ev ? fmt(ev.end) : '10:00';\n  $('#ed-subs').innerHTML = '';\n  (ev && ev.subs ? ev.subs : []).forEach(addSubRow);\n  $('#ed-delete').style.display = ev ? 'block' : 'none';\n  $('#ed-error').classList.remove('show');\n  $('#editor').classList.add('show');\n}\nfunction closeEditor(){ $('#editor').classList.remove('show'); editing = null; }\n\nfunction edError(msg){\n  const el = $('#ed-error');\n  el.textContent = msg;\n  el.classList.add('show');\n}\n\n$('#ed-save').addEventListener('click', () => {\n  const title = $('#ed-name').value.trim();\n  if(!title) return edError('タイトルを入力してください');\n  if(!$('#ed-start').value || !$('#ed-end').value) return edError('開始と終了の時間を入力してください');\n  const start = toMin($('#ed-start').value), end = toMin($('#ed-end').value);\n  if(start === end) return edError('開始と終了が同じ時間です');\n\n  const subs = [...document.querySelectorAll('#ed-subs .sub-edit')].map(r => ({\n    name: r.querySelector('.se-name').value.trim(),\n    start: r.querySelector('.se-start').value ? toMin(r.querySelector('.se-start').value) : start,\n    end: r.querySelector('.se-end').value ? toMin(r.querySelector('.se-end').value) : end,\n  })).filter(s => s.name);\n\n  if(editing){\n    Object.assign(editing, {title, cat: edCat, start, end});\n    if(subs.length) editing.subs = subs; else delete editing.subs;\n  }else{\n    const e = {id: 'ev' + Date.now(), title, cat: edCat, start, end};\n    if(subs.length) e.subs = subs;\n    SCHEDULE.push(e);\n  }\n  persistSchedule();\n  closeEditor();\n});\n\n$('#ed-delete').addEventListener('click', () => {\n  if(!editing) return;\n  if(!confirm(`「${editing.title}」を削除しますか?`)) return;\n  SCHEDULE = SCHEDULE.filter(e => e !== editing);\n  persistSchedule();\n  closeEditor();\n});\n\n$('#ed-cancel').addEventListener('click', closeEditor);\n$('#editor').addEventListener('click', e => { if(e.target === $('#editor')) closeEditor(); });\n$('#fab-add').addEventListener('click', () => openEditor(null));\n\n// ○タップで完了トグル / スキップ・持ち越し / 集中タイマー / カードをタップで編集\n$('#timeline').addEventListener('click', e => {\n  const chk = e.target.closest('.s-check, .ev-check');\n  if(chk){\n    const r = chk.getBoundingClientRect();\n    toggleDone(chk.dataset.key, {x: r.left + r.width/2, y: r.top + r.height/2});\n    return;\n  }\n  const skipBtn = e.target.closest('[data-skip]');\n  if(skipBtn){ setSkip(skipBtn.dataset.skip, 'skip'); return; }\n  const carryBtn = e.target.closest('[data-carry]');\n  if(carryBtn){\n    const ev = SCHEDULE.find(x => x.id === carryBtn.dataset.carry);\n    if(ev) sendToTomorrow(ev);\n    return;\n  }\n  const unskipBtn = e.target.closest('[data-unskip]');\n  if(unskipBtn){ setSkip(unskipBtn.dataset.unskip, null); return; }\n  const focusBtn = e.target.closest('[data-focus]');\n  if(focusBtn){ openFocus(focusBtn.dataset.focus); return; }\n  const item = e.target.closest('.tl-item');\n  if(!item) return;\n  const ev = SCHEDULE.find(x => x.id === item.dataset.id);\n  if(ev) openEditor(ev);\n});\n\n// 持ち越しタスクのチェック\n$('#carry-wrap').addEventListener('click', e => {\n  const b = e.target.closest('[data-carry-i]');\n  if(!b) return;\n  const carry = store.get('carry', null);\n  if(!carry) return;\n  const it = carry.items[+b.dataset.carryI];\n  it.done = !it.done;\n  store.set('carry', carry);\n  addXP(it.done ? 10 : -10);\n  if(it.done){\n    const r = b.getBoundingClientRect();\n    confettiBurst(r.left + r.width/2, r.top + r.height/2);\n  }\n  refreshHome();\n});\n\n/* ================= 集中タイマー(ポモドーロ) ================= */\nlet focusLeft = 25*60, focusTotal = 25*60, focusTimer = null, focusPhase = 'work';\nconst fFmt = s => `${Math.floor(s/60)}:${String(s%60).padStart(2,'0')}`;\nfunction focusRender(){\n  $('#focus-time').textContent = fFmt(focusLeft);\n  $('#focus-phase').textContent = focusPhase === 'work' ? 'FOCUS' : 'BREAK ☕';\n}\nfunction openFocus(taskName){\n  $('#focus-task').textContent = taskName || '';\n  focusPhase = 'work';\n  focusLeft = focusTotal;\n  $('#focus-hint').textContent = 'まずは始めるだけでOK。終わったら5分休憩';\n  $('#focus-start').textContent = '開始';\n  focusRender();\n  $('#focus').classList.add('show');\n}\nfunction stopFocus(){ clearInterval(focusTimer); focusTimer = null; }\n$('#focus-presets').addEventListener('click', e => {\n  const b = e.target.closest('button'); if(!b) return;\n  document.querySelectorAll('#focus-presets .btn').forEach(x => x.classList.toggle('sel', x === b));\n  focusTotal = +b.dataset.fmin * 60;\n  if(focusPhase === 'work' && !focusTimer){ focusLeft = focusTotal; focusRender(); }\n});\n$('#focus-start').addEventListener('click', () => {\n  if(focusTimer){ stopFocus(); $('#focus-start').textContent = '再開'; return; }\n  $('#focus-start').textContent = '一時停止';\n  focusTimer = setInterval(() => {\n    focusLeft--;\n    focusRender();\n    if(focusLeft > 0) return;\n    stopFocus();\n    if(focusPhase === 'work'){\n      addXP(20);\n      confettiBurst(innerWidth/2, innerHeight/2, 30);\n      focusPhase = 'break';\n      focusLeft = 5*60;\n      $('#focus-hint').textContent = 'おつかれさま!+20XP 🎉 5分休憩しよう';\n      $('#focus-start').textContent = '一時停止';\n      focusRender();\n      focusTimer = setInterval(() => {\n        focusLeft--;\n        focusRender();\n        if(focusLeft <= 0){\n          stopFocus();\n          $('#focus-hint').textContent = '休憩おわり。次の一歩へ 🌿';\n          $('#focus-start').textContent = '開始';\n          focusPhase = 'work';\n          focusLeft = focusTotal;\n        }\n      }, 1000);\n    }\n  }, 1000);\n});\n$('#focus-close').addEventListener('click', () => { stopFocus(); $('#focus').classList.remove('show'); $('#focus-start').textContent = '開始'; });\n$('#focus').addEventListener('click', e => { if(e.target === $('#focus')){ stopFocus(); $('#focus').classList.remove('show'); $('#focus-start').textContent = '開始'; } });\n\n// タイムライン / 24Hグラフ 切り替え\nfunction setView(v){\n  store.set('view', v);\n  $('#tab-tl').classList.toggle('sel', v === 'tl');\n  $('#tab-clock').classList.toggle('sel', v === 'clock');\n  $('#view-tl').style.display = v === 'tl' ? '' : 'none';\n  $('#view-clock').style.display = v === 'clock' ? '' : 'none';\n}\n$('#tab-tl').addEventListener('click', () => { setView('tl'); scrollToNow(); });\n$('#tab-clock').addEventListener('click', () => setView('clock'));\n\n// 達成率(チェックした数 / チェック対象の数。睡眠は対象外)\nfunction renderAch(){\n  let total = 0, done = 0;\n  for(const e of SCHEDULE){\n    if(e.cat === 'sleep' || skipStateOf(e.id)) continue; // スキップした予定はノーカウント\n    if(e.subs && e.subs.length){\n      total += e.subs.length;\n      e.subs.forEach((s,i) => { if(isDone(e.id + '/' + i)) done++; });\n    }else{\n      total++;\n      if(isDone(e.id)) done++;\n    }\n  }\n  // 持ち越しタスクも達成率に含める\n  const carry = store.get('carry', null);\n  if(carry && carry.date === todayKey()){\n    total += carry.items.length;\n    done += carry.items.filter(it => it.done).length;\n  }\n  const pct = total ? Math.round(done / total * 100) : 0;\n  $('#ach-pct').textContent = pct + '%';\n  $('#ach-fill').style.width = pct + '%';\n  $('#ach-meta').textContent = `${done}/${total} 完了${pct === 100 ? ' 🎉' : ''}`;\n  // マンスリーカレンダー用に日別履歴を記録\n  if(total){\n    const h = store.get('history', {});\n    h[todayKey()] = {pct, done, total};\n    store.set('history', h);\n  }\n}\n\n/* ================= マンスリー達成率カレンダー ================= */\nlet calMonth = new Date();\nfunction renderCalendar(){\n  const y = calMonth.getFullYear(), m = calMonth.getMonth();\n  const today = new Date();\n  const hist = store.get('history', {});\n  $('#cal-title').textContent = `${y}年${m + 1}月`;\n  $('#cal-dow').innerHTML = '日月火水木金土'.split('').map((d,i) =>\n    `<div class=\"cal-dow\" style=\"${i===0?'color:var(--c-workout)':i===6?'color:var(--c-work)':''}\">${d}</div>`).join('');\n\n  const firstDow = new Date(y, m, 1).getDay();\n  const days = new Date(y, m + 1, 0).getDate();\n  let html = '';\n  for(let i = 0; i < firstDow; i++) html += '<div class=\"cal-cell empty\"></div>';\n  let sum = 0, cnt = 0;\n  for(let d = 1; d <= days; d++){\n    const key = `${y}-${m + 1}-${d}`;\n    const rec = hist[key];\n    const isToday = y === today.getFullYear() && m === today.getMonth() && d === today.getDate();\n    const isFuture = new Date(y, m, d) > today;\n    if(rec){ sum += rec.pct; cnt++; }\n    const bg = rec ? `background:color-mix(in srgb,var(--brand) ${rec.pct}%,var(--surface))` : '';\n    const pTxt = rec ? `<span class=\"p\" style=\"color:${rec.pct >= 55 ? '#0d1017' : 'var(--brand)'}\">${rec.pct}%</span>` : (isFuture ? '' : '<span class=\"p\" style=\"color:var(--ink-3)\">–</span>');\n    const dCol = rec && rec.pct >= 55 ? '#0d1017' : '';\n    html += `<div class=\"cal-cell${isToday ? ' today' : ''}\" style=\"${bg}\"><span class=\"d\"${dCol ? ` style=\"color:${dCol}\"` : ''}>${d}</span>${pTxt}</div>`;\n  }\n  $('#cal-grid').innerHTML = html;\n  $('#cal-avg').textContent = cnt ? Math.round(sum / cnt) + '%' : '–';\n\n  // 連続記録(1日の休みは許容、2日連続で途切れる)\n  let streak = 0, miss = 0;\n  for(let i = 0; i < 366; i++){\n    const d = new Date(Date.now() - i * 86400000);\n    const rec = hist[`${d.getFullYear()}-${d.getMonth()+1}-${d.getDate()}`];\n    if(rec && rec.done > 0){ streak++; miss = 0; }\n    else if(i > 0){ miss++; if(miss >= 2) break; }\n  }\n  $('#cal-streak').textContent = streak ? `${streak}日` : '–';\n\n  // 直近7日の平均\n  let wSum = 0, wCnt = 0;\n  for(let i = 0; i < 7; i++){\n    const d = new Date(Date.now() - i * 86400000);\n    const rec = hist[`${d.getFullYear()}-${d.getMonth()+1}-${d.getDate()}`];\n    if(rec){ wSum += rec.pct; wCnt++; }\n  }\n  $('#cal-week').textContent = wCnt ? Math.round(wSum / wCnt) + '%' : '–';\n}\n$('#cal-prev').addEventListener('click', () => { calMonth = new Date(calMonth.getFullYear(), calMonth.getMonth() - 1, 1); renderCalendar(); });\n$('#cal-next').addEventListener('click', () => { calMonth = new Date(calMonth.getFullYear(), calMonth.getMonth() + 1, 1); renderCalendar(); });\n\n/* ================= スケジュールテンプレート ================= */\nfunction renderTemplates(){\n  const tpls = store.get('templates', [null, null, null]);\n  $('#tpl-list').innerHTML = tpls.map((t, i) => `\n    <div class=\"setting-row\">\n      <span style=\"font-size:13px\">${t ? '📋 ' + esc(t.name) : `スロット${i + 1}(空き)`}</span>\n      <span style=\"display:flex;gap:6px\">\n        <button class=\"btn sm\" data-tpl-save=\"${i}\">${t ? '上書き' : '保存'}</button>\n        ${t ? `<button class=\"btn sm primary\" data-tpl-load=\"${i}\">読み込み</button><button class=\"btn sm danger\" data-tpl-del=\"${i}\">削除</button>` : ''}\n      </span>\n    </div>`).join('');\n}\n$('#tpl-list').addEventListener('click', e => {\n  const b = e.target.closest('button'); if(!b) return;\n  const tpls = store.get('templates', [null, null, null]);\n  if(b.dataset.tplSave != null){\n    const i = +b.dataset.tplSave;\n    const name = prompt('テンプレート名を入力', tpls[i] ? tpls[i].name : `テンプレート${i + 1}`);\n    if(!name) return;\n    tpls[i] = {name: name.trim(), schedule: JSON.parse(JSON.stringify(SCHEDULE))};\n    store.set('templates', tpls);\n    renderTemplates();\n  }else if(b.dataset.tplLoad != null){\n    const t = tpls[+b.dataset.tplLoad];\n    if(!t || !confirm(`「${t.name}」を読み込みますか?\\n今のスケジュールは置き換わります`)) return;\n    SCHEDULE = JSON.parse(JSON.stringify(t.schedule));\n    persistSchedule();\n    renderTemplates();\n    alert(`「${t.name}」を読み込みました`);\n  }else if(b.dataset.tplDel != null){\n    const i = +b.dataset.tplDel;\n    if(!tpls[i] || !confirm(`「${tpls[i].name}」を削除しますか?`)) return;\n    tpls[i] = null;\n    store.set('templates', tpls);\n    renderTemplates();\n  }\n});\n\n/* ================= Googleカレンダー連携 (.ics読み込み) ================= */\nfunction parseICS(text){\n  // 折り返し行(継続行)を結合してからVEVENTを抽出\n  const lines = text.replace(/\\r\\n[ \\t]/g, '').replace(/\\n[ \\t]/g, '').replace(/\\r/g, '').split('\\n');\n  const events = [];\n  let cur = null;\n  for(const ln of lines){\n    if(ln === 'BEGIN:VEVENT') cur = {};\n    else if(ln === 'END:VEVENT'){ if(cur) events.push(cur); cur = null; }\n    else if(cur){\n      const i = ln.indexOf(':');\n      if(i < 0) continue;\n      const name = ln.slice(0, i).split(';')[0];\n      const val = ln.slice(i + 1);\n      if(name === 'SUMMARY') cur.summary = val.replace(/\\\\,/g, ',').replace(/\\\\;/g, ';').replace(/\\\\n/g, ' ');\n      else if(name === 'DTSTART') cur.dtstart = val;\n      else if(name === 'DTEND') cur.dtend = val;\n      else if(name === 'UID') cur.uid = val;\n    }\n  }\n  return events;\n}\n\nfunction icsToDate(v){\n  if(!v) return null;\n  if(/^\\d{8}$/.test(v)) return {allDay: true};\n  const m = v.match(/^(\\d{4})(\\d\\d)(\\d\\d)T(\\d\\d)(\\d\\d)(\\d\\d)?(Z)?$/);\n  if(!m) return null;\n  const d = m[7] === 'Z'\n    ? new Date(Date.UTC(+m[1], +m[2]-1, +m[3], +m[4], +m[5], +(m[6]||0)))\n    : new Date(+m[1], +m[2]-1, +m[3], +m[4], +m[5]); // TZID付きは端末のタイムゾーンとして扱う\n  return {date: d};\n}\n\nfunction importICS(text){\n  const today = new Date();\n  const sameDay = d => d.getFullYear() === today.getFullYear() && d.getMonth() === today.getMonth() && d.getDate() === today.getDate();\n  let added = 0, skipped = 0;\n  for(const ev of parseICS(text)){\n    const s = icsToDate(ev.dtstart);\n    if(!s || s.allDay || !s.date || !sameDay(s.date)){ skipped++; continue; }\n    const e = icsToDate(ev.dtend);\n    const start = s.date.getHours() * 60 + s.date.getMinutes();\n    let end = (e && e.date && !e.allDay) ? e.date.getHours() * 60 + e.date.getMinutes() : (start + 60) % 1440;\n    if(end === start) end = (start + 30) % 1440;\n    const id = 'gcal-' + (ev.uid || ev.summary + start) + '-' + todayKey();\n    if(SCHEDULE.some(x => x.id === id)) { skipped++; continue; }\n    SCHEDULE.push({id, cat: 'meeting', title: ev.summary || '(無題の予定)', start, end});\n    added++;\n  }\n  if(added) persistSchedule();\n  const r = $('#ics-result');\n  r.style.display = 'block';\n  r.textContent = added\n    ? `✓ 今日の予定を ${added}件 取り込みました(タイムラインに黄緑で表示されます)`\n    : '今日の日付の予定が見つかりませんでした(終日予定・他の日の予定は取り込まれません)';\n}\n\n$('#ics-import').addEventListener('click', () => $('#ics-file').click());\n$('#ics-file').addEventListener('change', e => {\n  const f = e.target.files[0];\n  if(!f) return;\n  const reader = new FileReader();\n  reader.onload = () => importICS(reader.result);\n  reader.readAsText(f);\n  e.target.value = '';\n});\n\n// 通知のテスト(Expo版のみ)\n$('#notify-test').addEventListener('click', () => {\n  if(!window.ReactNativeWebView){\n    $('#notify-status').textContent = 'ここはWeb版なので通知は動きません。Expo版アプリで押してください';\n    return;\n  }\n  window.ReactNativeWebView.postMessage(JSON.stringify({type: 'test'}));\n  $('#notify-status').textContent = 'テスト通知をリクエスト中…';\n});\n\n// スケジュールを初期状態に戻す\n$('#reset-schedule').addEventListener('click', () => {\n  if(!confirm('編集した内容をすべて消して、最初のスケジュールに戻します。よろしいですか?')) return;\n  localStorage.removeItem('adhdo.schedule');\n  SCHEDULE = JSON.parse(JSON.stringify(DEFAULT_SCHEDULE));\n  refreshHome();\n  renderLegend();\n});\n\n/* ================= 起動・更新 ================= */\nfunction refreshHome(){\n  const d = new Date();\n  // 日付が変わったら完了チェックをリセット\n  if(doneData.date !== todayKey()){\n    doneData = {date: todayKey(), items: {}, skips: {}};\n    store.set('done', doneData);\n  }\n  $('#home-date').textContent = `${d.getFullYear()}年${d.getMonth()+1}月${d.getDate()}日 (${'日月火水木金土'[d.getDay()]})`;\n  $('#diary-date').textContent = `${d.getMonth()+1}月${d.getDate()}日`;\n  renderTimeline();\n  renderClock();\n  renderAch();\n}\n// 秒つきリアルタイム時計\nfunction tickClock(){\n  const d = new Date();\n  $('#home-clock').textContent =\n    `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}:${String(d.getSeconds()).padStart(2,'0')}`;\n}\n\nsetView(store.get('view', 'tl'));\nrefreshHome();\nrenderLegend();\nrenderDiary();\nrenderAffirm();\nrenderTemplates();\nrenderLevel();\ntickClock();\nsetInterval(tickClock, 1000);\nsetTimeout(() => scrollToNow(false), 120);\nsetInterval(() => { if($('#scr-home').classList.contains('active')) refreshHome(); }, 30000);\nsyncNative();\n</script>\n</body>\n</html>\n";
